-- Function to parse XML and extract data
local function parse_xml_request()
    -- Get the request body
    local xml_data = ngx.req.get_body_data()

    if not xml_data then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Invalid request: No XML data found")
        return
    end

    -- Parse the XML data
    local parsed_xml, err = xml.load(xml_data)
    if not parsed_xml then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Invalid XML: " .. tostring(err))
        return
    end

    -- Extract data from the parsed XML
    local function extract_data(node, tag_name)
        for child in node:children() do
            if child:name() == tag_name then
                return child:text()
            else
                local result = extract_data(child, tag_name)
                if result then
                    return result
                end
            end
        end
    end

    -- Example extraction of data from specific tags
    local some_value = extract_data(parsed_xml, "SomeTag")
    ngx.say("Extracted value: " .. tostring(some_value))
end

